class StripeError(Exception):
    def __init__(self, e):
        self.status_code = e.response.status_code
        try: self.err = e.response.json().get('error', {})
        except Exception: self.err = {}
        self.msg = self.err.get('message', str(e))
        self.param = self.err.get('param')
        self.type = self.err.get('type')
        super().__init__(self.msg)

    def __str__(self):
        s = f"StripeError({self.status_code}): {self.msg}"
        if self.param: s += f" [param: {self.param}]"
        return s

class StripeSignatureError(Exception): pass

