def camel(s): return s.replace('.','_').replace('_',' ').title().replace(' ','')

class StripeObject(AttrDict):
    def __repr__(self): return f"{type(self).__name__}(id={self.get('id')})"

obj_typs = sorted({e for s in sspec['components']['schemas'].values()
                   for e in s.get('properties', {}).get('object', {}).get('enum', [])})
_objs = {o: type(camel(o), (StripeObject,), {}) for o in obj_typs}

def s2obj(x):
    if isinstance(x, list): return L(x).map(s2obj)
    if not isinstance(x, dict): return x
    o = x.get('object')
    d = AttrDict({k:s2obj(v) for k,v in x.items()})
    if not isinstance(o, str): return d
    res = _objs.get(o, StripeObject)(d)
    if o=='event' and 'data' in res and 'object' in res.data: res.data = res.data.object
    return res

