def _form_encoder(data, prefix=''):
    'Flatten a dictionary of data so that it can be used in a request body.'
    if not data: return {}
    result = {}
    for k,v in data.items():
        key = f'{prefix}[{k}]' if prefix else k
        if isinstance(v, dict): result.update(_form_encoder(v, key))
        elif isinstance(v, list): 
            for i,item in enumerate(v):
                if isinstance(item, dict): result.update(_form_encoder(item, f'{key}[{i}]'))
                else: result[f'{key}[{i}]'] = item
        else: result[key] = v
    return result

class StripeTransport(AsyncTransport):
    async def request(self, *args, raw=False, **kwargs):
        try: res = await super().request(*args, raw=raw, **kwargs)
        except httpx.HTTPStatusError as e: raise StripeError(e) from None
        return res if raw else s2obj(res)

class StripeApi(OpenAPIClient):
    def __init__(self, api_key=None, webhook_key=None, publishable_key=None,
                 service_name='faststripe', headers=None, timeout=60.0):
        self.api_key = ifnone(api_key, os.getenv('STRIPE_SECRET_KEY', os.getenv('STRIPE_API_KEY')))
        self.webhook_key = ifnone(webhook_key, os.getenv('STRIPE_WEBHOOK_SECRET', os.getenv('STRIPE_WEBHOOK_KEY')))
        self.publishable_key = ifnone(publishable_key, os.getenv('STRIPE_PUBLISHABLE_KEY'))
        self.service_name = service_name
        self.headers = {'Authorization': f'Bearer {self.api_key}'}
        self.headers |= headers or {}
        self.transport = StripeTransport(timeout=timeout, base_headers=self.headers)
        self.ops = [OpFunc(o, self.transport, pspec.base_url, _form_encoder) for o in pspec.ops]
        self.func_dict = {f"{o.path}:{o.verb.upper()}": o for o in self.ops}
        self.groups = _build_groups(self.ops)
        for k,v in self.groups.items(): setattr(self, k, v)

