async def paged(oper, *args, **kwargs):
    """Iterate through all pages of a Stripe API operation."""
    page = await oper(*args, **kwargs)
    yield page
    while page.has_more:
        last_id = page.data[-1].id
        page = await oper(*args, starting_after=last_id, **kwargs)
        yield page

# %% ../nbs/01_core.ipynb #5b2bae88
async def pages(oper, *args, **kwargs):
    "Retrieve all items from all pages of a Stripe API operation."
    return L([x async for page in paged(oper, *args, **kwargs) for x in page.data])

