def _metadata(evt):
    "Return metadata used for service routing from a Stripe event or object."
    obj = getattr(evt, 'data', evt)
    return getattr(obj, 'metadata', None) or getattr(evt, 'metadata', None) or {}

@patch
def filter_evt(self:StripeApi, evt):
    "Return True if `evt` belongs to this StripeApi service."
    if not self.service_name: return True
    return _metadata(evt).get("STRIPE_SERVICE_NAME") == self.service_name

